window.bookSummaryJSON = "<p><i>Dream Serenade</i> is an all-night-long soundscape created by sound therapy composer Rich Lucano.</p> <p>Composed to cocoon you in ambient soundscapes and gentle orchestral waves, specially designed to help you relax, fall asleep and stay asleep. Press play to take a gentle sonic journey that will serenade you to sleep.</p> <p>Suitable for listeners of all ages.</p>"; 
